import{_ as t,o,c as a,a2 as n}from"./chunks/framework.B72_uj9U.js";const u=JSON.parse('{"title":"Codex CLI Architecture Analysis","description":"","frontmatter":{"title":"Codex CLI Architecture Analysis","status":"complete"},"headers":[],"relativePath":"research/agents/codex/index.md","filePath":"research/agents/codex/index.md"}'),r={name:"research/agents/codex/index.md"};function d(s,e,i,c,l,p){return o(),a("div",null,[...e[0]||(e[0]=[n(`<h1 id="codex-cli" tabindex="-1">Codex CLI <a class="header-anchor" href="#codex-cli" aria-label="Permalink to &quot;Codex CLI&quot;">​</a></h1><blockquote><p>OpenAI&#39;s official terminal-native coding agent — open-source, Rust-native, with OS-level sandboxing.</p></blockquote><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p><strong>Codex CLI</strong> is OpenAI&#39;s locally-running coding agent for the terminal. It reads, modifies, and executes code on your machine inside a sandboxed environment. Originally built in TypeScript (the <code>codex-cli/</code> directory, now legacy), the production implementation is written entirely in <strong>Rust</strong> (<code>codex-rs/</code>), compiled to a single static binary with zero runtime dependencies.</p><table tabindex="0"><thead><tr><th>Property</th><th>Value</th></tr></thead><tbody><tr><td><strong>Repository</strong></td><td><a href="https://github.com/openai/codex" target="_blank" rel="noreferrer">github.com/openai/codex</a></td></tr><tr><td><strong>License</strong></td><td>Apache-2.0</td></tr><tr><td><strong>Language</strong></td><td>Rust (70+ crates in a Cargo workspace)</td></tr><tr><td><strong>UI Framework</strong></td><td><a href="https://ratatui.rs/" target="_blank" rel="noreferrer">Ratatui</a> (full-screen TUI)</td></tr><tr><td><strong>Build System</strong></td><td>Cargo + Bazel (dual build support)</td></tr><tr><td><strong>Install</strong></td><td><code>npm i -g @openai/codex</code> / <code>brew install --cask codex</code></td></tr><tr><td><strong>Platforms</strong></td><td>macOS, Linux, Windows (WSL + experimental native)</td></tr><tr><td><strong>API</strong></td><td>OpenAI Responses API (streaming SSE + WebSocket)</td></tr><tr><td><strong>MCP Support</strong></td><td>Client (connects to MCP servers) + Server (<code>codex mcp-server</code>)</td></tr></tbody></table><h2 id="openai-s-vision" tabindex="-1">OpenAI&#39;s Vision <a class="header-anchor" href="#openai-s-vision" aria-label="Permalink to &quot;OpenAI&#39;s Vision&quot;">​</a></h2><p>Codex CLI is part of OpenAI&#39;s &quot;Codex&quot; family that spans three form factors:</p><ol><li><strong>Codex CLI</strong> — local terminal agent (this project, open-source)</li><li><strong>Codex IDE</strong> — VS Code / Cursor / Windsurf extension</li><li><strong>Codex Cloud</strong> — cloud-hosted agent at chatgpt.com/codex</li></ol><p>The CLI is designed for developers who &quot;live in the terminal&quot; and want ChatGPT-level reasoning with the ability to actually execute code, manipulate files, and iterate — all under version control and OS-level sandboxing.</p><h2 id="language-stack" tabindex="-1">Language &amp; Stack <a class="header-anchor" href="#language-stack" aria-label="Permalink to &quot;Language &amp; Stack&quot;">​</a></h2><p>The codebase is a <strong>Cargo workspace with 70+ crates</strong>, organized as a monorepo:</p><table tabindex="0"><thead><tr><th>Crate</th><th>Role</th></tr></thead><tbody><tr><td><code>codex-core</code></td><td>Central orchestration — agent loop, session management, model client</td></tr><tr><td><code>codex-protocol</code></td><td>Shared types: SQ/EQ protocol, config enums, model metadata</td></tr><tr><td><code>codex-cli</code></td><td>Binary entry point + subcommand routing via <code>clap</code></td></tr><tr><td><code>codex-tui</code></td><td>Full-screen terminal UI built with Ratatui</td></tr><tr><td><code>codex-exec</code></td><td>Non-interactive <code>codex exec</code> mode for automation/CI</td></tr><tr><td><code>codex-exec-server</code></td><td>JSON-RPC exec server (WebSocket/stdio transport)</td></tr><tr><td><code>codex-config</code></td><td>Layered configuration system (TOML-based)</td></tr><tr><td><code>codex-execpolicy</code></td><td>Command approval policy engine with prefix-rule matching</td></tr><tr><td><code>codex-linux-sandbox</code></td><td>Linux sandbox: bubblewrap + seccomp + optional Landlock</td></tr><tr><td><code>codex-api</code></td><td>Typed client for OpenAI Responses, Compaction, Memory APIs</td></tr><tr><td><code>codex-mcp-server</code></td><td>Codex as an MCP server for other agents</td></tr><tr><td><code>windows-sandbox-rs</code></td><td>Windows sandbox: ACLs + firewall + restricted tokens</td></tr><tr><td><code>process-hardening</code></td><td>Pre-main security: disable ptrace, core dumps, LD_PRELOAD</td></tr></tbody></table><p>Key ecosystem dependencies: <code>tokio</code>, <code>ratatui</code>, <code>clap</code>, <code>reqwest</code>, <code>serde</code>, <code>landlock</code>, <code>seccompiler</code>, and vendored forks of <code>crossterm</code>/<code>ratatui</code>.</p><h2 id="sandboxing-model-key-differentiator" tabindex="-1">Sandboxing Model (Key Differentiator) <a class="header-anchor" href="#sandboxing-model-key-differentiator" aria-label="Permalink to &quot;Sandboxing Model (Key Differentiator)&quot;">​</a></h2><p>Codex CLI&#39;s <strong>defining feature</strong> is its multi-layered OS-level sandboxing that runs entirely locally — no containers, VMs, or cloud isolation needed:</p><h3 id="three-sandbox-modes" tabindex="-1">Three Sandbox Modes <a class="header-anchor" href="#three-sandbox-modes" aria-label="Permalink to &quot;Three Sandbox Modes&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Mode</th><th>Filesystem</th><th>Network</th></tr></thead><tbody><tr><td><code>read-only</code></td><td>Entire FS read-only</td><td>Blocked</td></tr><tr><td><code>workspace-write</code> (default)</td><td>CWD writable, rest read-only</td><td>Blocked</td></tr><tr><td><code>danger-full-access</code></td><td>No restrictions</td><td>Allowed</td></tr></tbody></table><h3 id="platform-specific-enforcement" tabindex="-1">Platform-Specific Enforcement <a class="header-anchor" href="#platform-specific-enforcement" aria-label="Permalink to &quot;Platform-Specific Enforcement&quot;">​</a></h3><ul><li><strong>macOS</strong>: Apple Seatbelt (<code>sandbox-exec</code>) with custom profiles. Read-only jail with explicit writable roots (<code>$PWD</code>, <code>$TMPDIR</code>, <code>~/.codex</code>). All network blocked.</li><li><strong>Linux</strong>: Bubblewrap (mount/user/PID/network namespaces) + seccomp syscall filtering + optional Landlock. Blocks <code>ptrace</code>, <code>io_uring</code>, and all network syscalls except <code>AF_UNIX</code>.</li><li><strong>Windows</strong>: Dedicated sandbox user accounts + Windows ACL Deny ACEs + Windows Firewall per-SID outbound block rules + alternate desktop isolation + restricted security tokens.</li></ul><h3 id="protected-paths" tabindex="-1">Protected Paths <a class="header-anchor" href="#protected-paths" aria-label="Permalink to &quot;Protected Paths&quot;">​</a></h3><p>Even in <code>workspace-write</code> mode, sensitive paths remain read-only:</p><ul><li><code>.git/</code> (and resolved <code>gitdir:</code> targets)</li><li><code>.codex/</code> and <code>.agents/</code> directories</li><li>Protection is recursive</li></ul><h3 id="process-hardening-pre-main" tabindex="-1">Process Hardening (Pre-Main) <a class="header-anchor" href="#process-hardening-pre-main" aria-label="Permalink to &quot;Process Hardening (Pre-Main)&quot;">​</a></h3><p>Applied via <code>#[ctor::ctor]</code> before <code>main()</code>:</p><ul><li><strong>Linux</strong>: <code>PR_SET_DUMPABLE=0</code>, <code>RLIMIT_CORE=0</code>, strip all <code>LD_*</code> env vars</li><li><strong>macOS</strong>: <code>PT_DENY_ATTACH</code>, <code>RLIMIT_CORE=0</code>, strip all <code>DYLD_*</code> env vars</li><li>Prevents debugger attachment, core dumps, and shared-library injection</li></ul><h2 id="terminal-bench-2-0-scores" tabindex="-1">Terminal-Bench 2.0 Scores <a class="header-anchor" href="#terminal-bench-2-0-scores" aria-label="Permalink to &quot;Terminal-Bench 2.0 Scores&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Rank</th><th>Model</th><th>Score</th></tr></thead><tbody><tr><td>#27</td><td>GPT-5.2</td><td>62.9%</td></tr><tr><td>#34</td><td>GPT-5.1-Codex-Max</td><td>60.4%</td></tr><tr><td>#53</td><td>GPT-5</td><td>49.6%</td></tr></tbody></table><h2 id="key-features" tabindex="-1">Key Features <a class="header-anchor" href="#key-features" aria-label="Permalink to &quot;Key Features&quot;">​</a></h2><ul><li><strong>Interactive TUI</strong>: Full-screen terminal UI with syntax highlighting, diff rendering, theme support (<code>/theme</code>), and image input</li><li><strong>Non-interactive mode</strong>: <code>codex exec PROMPT</code> for CI/scripting</li><li><strong>Resume sessions</strong>: <code>codex resume</code> picks up prior transcript and context</li><li><strong>Sub-agents</strong>: Spawn parallel agent threads for complex multi-file tasks</li><li><strong>Web search</strong>: Built-in tool with cached/live/disabled modes</li><li><strong>Code review</strong>: Dedicated <code>/review</code> command with branch diff, uncommitted changes, and commit review modes</li><li><strong>MCP client + server</strong>: Connect to external tools; run Codex as a tool for other agents</li><li><strong>Multi-model</strong>: GPT-5.4 (recommended), GPT-5.3-Codex, GPT-5.2-Codex, Ollama, LM Studio, and any OpenAI-compatible provider</li><li><strong>Approval policies</strong>: <code>on-request</code> (default), <code>untrusted</code>, <code>never</code>, granular per-category</li><li><strong>Enterprise features</strong>: OTel telemetry, managed config requirements (MDM), custom CA certificates, SQLite state persistence</li><li><strong>Slash commands</strong>: <code>/review</code>, <code>/fork</code>, <code>/model</code>, <code>/permissions</code>, <code>/clear</code>, <code>/copy</code>, <code>/status</code>, custom user-defined commands</li></ul><h2 id="architecture-at-a-glance" tabindex="-1">Architecture at a Glance <a class="header-anchor" href="#architecture-at-a-glance" aria-label="Permalink to &quot;Architecture at a Glance&quot;">​</a></h2><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>┌─────────────┐    SQ/EQ     ┌──────────────┐</span></span>
<span class="line"><span>│  TUI / CLI  │◄────────────►│  codex-core   │</span></span>
<span class="line"><span>│  (Ratatui)  │  (channels)  │  (Session)    │</span></span>
<span class="line"><span>└─────────────┘              │               │</span></span>
<span class="line"><span>                             │  ┌──────────┐ │     ┌─────────────────┐</span></span>
<span class="line"><span>                             │  │ToolRouter│─┼────►│ ExecPolicy      │</span></span>
<span class="line"><span>                             │  └──────────┘ │     │ (rule matching) │</span></span>
<span class="line"><span>                             │               │     └─────────────────┘</span></span>
<span class="line"><span>                             │  ┌──────────┐ │     ┌─────────────────┐</span></span>
<span class="line"><span>                             │  │ToolOrch. │─┼────►│ SandboxManager  │</span></span>
<span class="line"><span>                             │  └──────────┘ │     │ (OS-level)      │</span></span>
<span class="line"><span>                             │               │     └─────────────────┘</span></span>
<span class="line"><span>                             │  ┌──────────┐ │     ┌─────────────────┐</span></span>
<span class="line"><span>                             │  │ContextMgr│─┼────►│ codex-api       │</span></span>
<span class="line"><span>                             │  └──────────┘ │     │ (Responses API) │</span></span>
<span class="line"><span>                             └──────────────┘     └─────────────────┘</span></span></code></pre></div><p>The SQ/EQ (Submission Queue / Event Queue) pattern decouples the UI from the agent core. The UI submits <code>Op</code> variants (user input, approvals, config changes) and receives <code>EventMsg</code> variants (agent messages, approval requests, token usage).</p><h2 id="see-also" tabindex="-1">See Also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See Also&quot;">​</a></h2><ul><li><a href="./architecture.html">Architecture</a> — Full architecture deep-dive</li><li><a href="./agentic-loop.html">Agentic Loop</a> — Agent loop implementation details</li><li><a href="./tool-system.html">Tool System</a> — Tools, sandboxing, and execution policy</li><li><a href="./context-management.html">Context Management</a> — Token management and compaction</li><li><a href="./unique-patterns.html">Unique Patterns</a> — Key differentiators vs other agents</li><li><a href="./benchmarks.html">Benchmarks</a> — Performance data</li><li><a href="./references.html">References</a> — Links and resources</li></ul>`,34)])])}const g=t(r,[["render",d]]);export{u as __pageData,g as default};
